import { SectionConfig } from './section-schemas';

export interface BuilderPageData {
  id: string;
  title: string;
  slug: string;
  status: 'published' | 'draft';
  language: 'en' | 'ar' | 'fa';
  builderData: SectionConfig[];
  isBuilderPage: boolean;
  builderVersion?: string;
}

/**
 * Load page data for builder
 */
export async function loadBuilderPage(pageId: string): Promise<BuilderPageData | null> {
  try {
    const token = localStorage.getItem('adminToken');
    if (!token) throw new Error('No auth token');

    const response = await fetch(`/api/admin/pages/${pageId}/builder`, {
      headers: {
        'Authorization': `Bearer ${token}`,
      },
    });

    if (!response.ok) {
      throw new Error(`Failed to load page: ${response.statusText}`);
    }

    const data = await response.json();
    return data.page;
  } catch (error) {
    console.error('Failed to load builder page:', error);
    return null;
  }
}

/**
 * Save builder page data
 */
export async function saveBuilderPage(
  pageId: string, 
  sections: SectionConfig[]
): Promise<boolean> {
  try {
    const token = localStorage.getItem('adminToken');
    if (!token) throw new Error('No auth token');

    const response = await fetch(`/api/admin/pages/${pageId}/builder`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
      },
      body: JSON.stringify({
        builderData: sections,
        isBuilderPage: true,
        builderVersion: '1.0',
      }),
    });

    if (!response.ok) {
      throw new Error(`Failed to save page: ${response.statusText}`);
    }

    return true;
  } catch (error) {
    console.error('Failed to save builder page:', error);
    return false;
  }
}

/**
 * Convert existing page to builder format
 */
export async function convertPageToBuilder(pageId: string): Promise<boolean> {
  try {
    const token = localStorage.getItem('adminToken');
    if (!token) throw new Error('No auth token');

    const response = await fetch(`/api/admin/pages/${pageId}/convert`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`,
      },
    });

    if (!response.ok) {
      throw new Error(`Failed to convert page: ${response.statusText}`);
    }

    return true;
  } catch (error) {
    console.error('Failed to convert page:', error);
    return false;
  }
}